const TRUNCATION_NOTICE = ' [truncated]';

function estimateTokens(text: string): number {
  return Math.ceil(text.length / 4);
}

function truncatePrompt(prompt: string, maxTokens: number): string {
  if (estimateTokens(prompt) <= maxTokens) return prompt;

  const noticeTokens = estimateTokens(TRUNCATION_NOTICE);
  const budget = maxTokens - noticeTokens;
  if (budget <= 0) return TRUNCATION_NOTICE.trim();

  // Try paragraph boundaries
  const paragraphs = prompt.split(/\n\n+/);
  let accumulated = '';
  for (const para of paragraphs) {
    const candidate = accumulated ? accumulated + '\n\n' + para : para;
    if (estimateTokens(candidate) <= budget) {
      accumulated = candidate;
    } else {
      break;
    }
  }
  if (accumulated && accumulated !== prompt) {
    return accumulated.trimEnd() + TRUNCATION_NOTICE;
  }

  // Try sentence boundaries
  const sentences = prompt.match(/[^.!?]+[.!?]+/g) || [];
  accumulated = '';
  for (const sent of sentences) {
    const candidate = accumulated + sent;
    if (estimateTokens(candidate) <= budget) {
      accumulated = candidate;
    } else {
      break;
    }
  }
  if (accumulated && accumulated.trim() !== prompt.trim()) {
    return accumulated.trimEnd() + TRUNCATION_NOTICE;
  }

  // Hard truncate at character boundary
  const maxChars = budget * 4;
  return prompt.slice(0, maxChars).trimEnd() + TRUNCATION_NOTICE;
}
